-- 1. Ashford × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'ashford',
  'Ashford is no longer the quiet market town it was twenty years ago. With a population approaching 85,000 and rapid expansion through developments like Finberry, Chilmington Green, and Park Farm, the town has become one of the fastest-growing commercial centres in Kent. Thousands of professionals commute to London St Pancras in just thirty-seven minutes via Ashford International Station, and they carry those metropolitan expectations home with them. When a Finberry resident searches for a local tradesperson or a County Square shopper looks up a nearby restaurant, they expect a website that loads instantly, looks polished, and makes booking effortless. We build bespoke, conversion-focused websites for Ashford businesses that meet those commuter-grade expectations and turn local search traffic into genuine paying customers.',
  'Ashford sits at the intersection of the M20 and the A2070, drawing customers from across east Kent and the Romney Marsh. The town centre is anchored by County Square Shopping Centre, the Elwick Place cinema and restaurant complex, and a growing number of independent businesses along the High Street. The Commercial Quarter and International House host professional service firms, while the surrounding new-build estates bring a younger, digitally native demographic. Ashford International Station provides high-speed rail links to London St Pancras in just 37 minutes, adding an international dimension to the local business community.',
  'Ashford''s web design market is split between London agencies offering premium rates for remote work and local freelancers competing primarily on price. Many established businesses around County Square and the High Street still run websites built five or more years ago that fail basic mobile usability tests. The new-build estates have brought tech-savvy residents who judge businesses harshly on digital presentation, creating a widening gap between firms with modern sites and those falling behind.',
  'Our approach for Ashford clients starts with understanding the commuter mindset. Residents who work in London expect seamless digital experiences. We build sites optimised for evening browsing on mobile devices, when commuters are researching local services on the train home. Postcode-level competitor analysis ensures your site outperforms rivals across Ashford, Finberry, and surrounding areas on speed, usability, and conversion.',
  '{"population": 85000, "growth": "Rapidly expanding via Finberry, Chilmington Green, Park Farm", "business_districts": ["County Square", "Commercial Quarter", "Elwick Place", "High Street", "International House"], "key_fact": "37 minutes to London St Pancras via Ashford International"}',
  '[{"title": "Outdated sites failing Ashford''s commuter expectations", "description": "Ashford''s commuter population compares every local website against the polished digital experiences they encounter in London. Businesses around County Square and the High Street with dated, clunky sites are losing customers to competitors who present a more professional online image."}, {"title": "Template websites invisible in a growing market", "description": "With thousands of new residents arriving through Finberry, Chilmington Green, and Park Farm, the pool of potential customers is expanding fast. But template websites with generic stock imagery cannot differentiate your business from the dozens of competitors these new residents are evaluating for the first time."}, {"title": "No mobile-first design for train-browsing commuters", "description": "A significant proportion of Ashford''s local searches happen on mobile devices during the thirty-seven-minute commute from London St Pancras. Websites that are not optimised for fast mobile loading and thumb-friendly navigation lose these high-intent evening searchers to competitors who are."}]',
  '[{"title": "Commuter-grade websites for Ashford businesses", "description": "We design and build websites that match the digital standards Ashford''s London commuters expect. Clean, modern design with sub-two-second load times, intuitive mobile navigation, and prominent calls to action that convert evening browsers into morning enquiries."}, {"title": "Conversion-focused design for a growing population", "description": "Every Ashford site we build is engineered around a clear conversion path. Whether your customers come from Finberry, Park Farm, or the town centre, we map their journey from search to enquiry and remove every friction point that could cost you a lead."}, {"title": "Bespoke visual identity reflecting Ashford credibility", "description": "No templates and no generic stock images. We create original designs that position your Ashford business as the established, trustworthy choice in a rapidly growing market. Real photography, authentic local references, and design that stands apart from every other Kent business website."}]',
  '[{"question": "How long does a new website take for an Ashford business?", "answer": "Most Ashford projects launch within four to six weeks. We start with a strategy session understanding your position in the local market, whether you serve the new-build estates, the town centre, or the wider east Kent area, then move through design, development, and testing."}, {"question": "Will my new site rank well for Ashford searches?", "answer": "Every site we build includes foundational on-page SEO: Ashford-specific title tags, structured data markup, optimised images, and local content. While rankings build over time, we typically see movement within four to eight weeks for targeted local terms."}, {"question": "Do you design for businesses outside Ashford town centre?", "answer": "Yes. Many of our Ashford clients serve surrounding areas including Tenterden, Wye, Hamstreet, and the new-build estates at Finberry and Chilmington Green. We build sites that target the specific postcodes and areas relevant to your service coverage."}, {"question": "Can you redesign my existing Ashford business website?", "answer": "Absolutely. We perform a full audit of your current site, preserving any existing search authority through proper redirects while delivering a modern, conversion-focused design that meets the expectations of Ashford''s growing and increasingly digital customer base."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
