-- 6. Ashford × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'ashford',
  'Social media is where Ashford''s new residents go to find and vet local businesses before they ever open Google. Facebook community groups for Finberry, Chilmington Green, and Park Farm are buzzing with recommendations requests daily. Instagram is where restaurants near Elwick Place and the High Street build their following. Yet the majority of Ashford businesses either have no social media presence at all, or have dormant profiles with outdated information and no consistent posting. In a town where thousands of new residents are actively seeking recommendations and forming opinions about local businesses online, a properly set up and branded social media presence is not optional. We build, optimise, and brand your social media profiles from scratch so your Ashford business is ready to be found, shared, and recommended.',
  'Ashford''s social media landscape is dominated by hyperlocal community groups. Facebook groups for Finberry Residents, Chilmington Green Community, and Park Farm Ashford have thousands of active members who regularly ask for trade recommendations, restaurant suggestions, and service provider referrals. Instagram drives footfall to the Elwick Place dining and entertainment venues. Google reviews influence search rankings. The commuter demographic is active on LinkedIn, creating opportunities for B2B businesses in the Commercial Quarter to build professional visibility.',
  'Social media maturity among Ashford businesses is low. Most trades have a Facebook page created years ago with no recent activity. Restaurants and retail businesses near County Square vary widely in their social media quality. Very few Ashford businesses have consistent branding across Facebook, Instagram, and Google Business Profile. This creates a significant opportunity for businesses willing to invest in proper setup and consistent presence.',
  'We set up social media for Ashford businesses based on where their customers actually spend time online. Trades targeting the new estates get Facebook profiles optimised for community group engagement. Hospitality businesses near Elwick Place get Instagram-first strategies with professional imagery. B2B firms in the Commercial Quarter get LinkedIn company pages built for credibility. Every profile is branded consistently and optimised for local discovery.',
  '{"population": 85000, "growth": "Active hyperlocal community groups on Facebook", "business_districts": ["Elwick Place", "County Square", "High Street", "Commercial Quarter"], "key_fact": "New estate Facebook groups are primary recommendation sources for residents"}',
  '[{"title": "Missing from Ashford community group recommendations", "description": "When a Finberry resident posts asking for a reliable plumber or a Chilmington Green family requests a restaurant recommendation, your business is invisible if it has no social media presence. These community groups generate genuine customer referrals daily, and businesses without profiles cannot participate."}, {"title": "Dormant profiles creating a negative impression", "description": "An Ashford business with a Facebook page last updated eighteen months ago sends a worse signal than having no page at all. Potential customers check social media to verify a business is active and legitimate. Dormant or poorly maintained profiles suggest the business may have closed or does not care about its reputation."}, {"title": "Inconsistent branding across social platforms", "description": "Different logos on Facebook, Instagram, and Google Business Profile. Outdated phone numbers on one platform, wrong address on another. Ashford businesses with inconsistent social media profiles confuse potential customers and undermine the trust needed to convert a recommendation into an enquiry."}]',
  '[{"title": "Community-group-ready Facebook profiles for Ashford", "description": "We build and optimise your Facebook business page specifically for engagement in Ashford''s hyperlocal community groups. Professional branding, complete service information, proper categorisation, and a content template library so you can respond to recommendation requests with a link to a profile that converts."}, {"title": "Platform-specific setup for your Ashford audience", "description": "Trades get Facebook-first setups for community group engagement. Restaurants near Elwick Place get Instagram profiles with professional food photography templates. Professional services in the Commercial Quarter get LinkedIn pages built for B2B credibility. Every platform is chosen and configured for your specific Ashford audience."}, {"title": "Consistent cross-platform brand presence", "description": "Same logo, same colours, same contact details, same messaging across every platform. We set up and brand your Facebook, Instagram, Google Business Profile, and LinkedIn with identical visual identity and accurate information, creating the consistent, professional impression that builds trust with Ashford customers."}]',
  '[{"question": "Which social media platforms should my Ashford business be on?", "answer": "It depends entirely on your customers. For trades targeting new estates, Facebook is essential because of the community groups. For hospitality near Elwick Place, Instagram drives footfall. For B2B services in the Commercial Quarter, LinkedIn builds credibility. We recommend the right platforms based on your specific Ashford market."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup: creating, branding, and optimising your profiles so they are ready to generate business. We also provide content templates and a posting guide so you can maintain your presence independently. Ongoing management is available as a separate service if needed."}, {"question": "How important are Google reviews for Ashford businesses?", "answer": "Extremely important. Google reviews directly influence your local search ranking and are often the deciding factor when Ashford residents compare businesses. We set up your Google Business Profile with optimised categories and a review generation strategy that makes it easy for satisfied customers to leave feedback."}, {"question": "Can you help me engage with Ashford community Facebook groups?", "answer": "We set up your profile so it is ready for community group engagement, including professional branding, complete service information, and portfolio images. We also provide guidance on how to respond to recommendation requests effectively. Direct group engagement should come from you personally, as authenticity is key in these local communities."}]',
  'trust'
)
